INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-f29af906-moex-00738', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '關於部分共有人就共有土地全部為處分、變更及設定地上權、農育權、不動產役權或典權申請登記時， 依土地登記規則之規定，下列敘述何者錯誤？', '["登記申請書及契約書內，應列明全體共有人", "登記申請書備註欄記明依土地法第34條之1第1項至第3項規定辦理", "提出已為書面通知或公告之證明文件，及他共有人應得對價或補償已受領或已提存之證明文件", "契約書及登記申請書上須有他共有人之簽名或蓋章"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00739', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依土地登記規則之規定，申請抵押權設定登記時，契約書訂有於債權已屆清償期而未為清償時，抵押物 之所有權移屬於抵押權人之約定者，登記機關應如何辦理？', '["登記機關應要求權利人與義務人提供切結書", "登記機關應停止登記程序，要求當事人提起訴訟", "登記機關應於登記簿記明之", "登記機關應要求權利人與義務人就約定事項辦理公證"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00740', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '下列何者非屬現行土地登記規則規定應辦理登記之土地權利？', '["典權", "耕作權", "抵當權", "農育權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00741', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依據複丈測量結果發現錯誤，登記機關依法更正地籍圖，下列法律關係之敘述，何者最為正確？', '["複丈僅事實地取得標的土地之空間資訊，並無直接對外法律效力，故為事實行為；更正地籍圖則僅係 登記機關依據測量結果之內部作業，故亦為事實行為", "複丈僅事實地取得標的土地之空間資訊，並無直接對外法律效力，故為事實行為；更正地籍圖則因變 動或確認私權範圍，涉及人民權利義務，故為行政處分", "複丈具對外法律效力，故為行政處分；更正地籍圖則因變動或確認私權範圍，涉及人民權利義務，故 為行政處分", "複丈具對外法律效力，故為行政處分；更正地籍圖則僅係登記機關依據測量結果之內部作業，故為事 實行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00742', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依都市計畫法之規定，私有公共設施保留地劃設逾多少年未經政府取得者，得申請與公有非公用土地優 先辦理交換？', '["10年", "15年", "20年", "25年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00743', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '不動產估價師開業證書期滿換證時，應檢附幾小時以上專業訓練證明文件，始得申請？', '["36小時", "30小時", "24小時", "20小時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00744', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依國土計畫法之規定，於國土保育地區申請使用許可，其使用許可之審議，應由下列何者為之？', '["內政部", "直轄市、縣（市）政府", "行政院", "行政院農業委員會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00745', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依都市計畫法規定，重大投資開發案件涉及都市計畫之擬定或變更，依法應辦理環境影響評估、實施水 土保持之處理與維護者，下列有關其程序之敘述，何者正確？', '["重大投資開發案件之認定辦法，攸關經濟發展，由經濟部訂定之", "為保障人民權益，重大投資開發者依法得申請平行作業方式辦理", "必要時得聯合作業，由都市計畫主管機關召集聯席會議審決之", "地方政府得視經濟發展之需要，逕依計畫確定裁決程序變更計畫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00746', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '都市更新事業計畫的核定，如果違法，原核定機關得為下列何種行為？', '["依職權廢止", "依職權撤銷", "訴請終止", "訴請撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00747', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '出租之公、私有耕地因直轄市或縣（市）政府實施市地重劃致不能達到原租賃之目的時，該如何處理？', '["出租人得解除租約，向直轄市或縣（市）政府請求賠償", "由直轄市或縣（市）政府逕為註銷其租約並通知當事人", "承租人得終止租約，向直轄市或縣（市）政府請求賠償", "由中央主管機關命出租人或承租人解約並通知地方政府"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
